<?php
 namespace League\CommonMark\Extension\DisallowedRawHtml; use League\CommonMark\ElementRendererInterface; use League\CommonMark\Inline\Element\AbstractInline; use League\CommonMark\Inline\Renderer\InlineRendererInterface; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; final class DisallowedRawHtmlInlineRenderer implements InlineRendererInterface, ConfigurationAwareInterface { private $htmlInlineRenderer; public function __construct(InlineRendererInterface $htmlBlockRenderer) { $this->htmlInlineRenderer = $htmlBlockRenderer; } public function render(AbstractInline $inline, ElementRendererInterface $htmlRenderer) { $rendered = $this->htmlInlineRenderer->render($inline, $htmlRenderer); if ($rendered === '') { return ''; } return preg_replace('/<(\/?(?:title|textarea|style|xmp|iframe|noembed|noframes|script|plaintext)[ \/>])/i', '&lt;$1', $rendered); } public function setConfiguration(ConfigurationInterface $configuration) { if ($this->htmlInlineRenderer instanceof ConfigurationAwareInterface) { $this->htmlInlineRenderer->setConfiguration($configuration); } } } 